// Keyboard_mouse.js
import React from 'react';

const Keyboard_mouse = () => {
  const handleKeyPress = (event) => {
    console.log(`Key pressed: ${event.key}`);
  };

  const handleMouseMove = (event) => {
    console.log(`Mouse moved to: (${event.clientX}, ${event.clientY})`);
  };

  return (
    <div
      className="keyboard-mouse-container"
      onKeyPress={handleKeyPress}
      onMouseMove={handleMouseMove}
      tabIndex="0" // important pentru a captura evenimentele tastaturii
      style={{ border: '1px solid black', padding: '20px' }}
    >
      <h2>Keyboard and Mouse Controller</h2>
      <p>Move your mouse or press any key to see the events logged in the console.</p>
    </div>
  );
};

export default Keyboard_mouse;
